#include <bits/stdc++.h>
using namespace std;
int n,m;
int s[500005],c[500005];
int Lowbit(int x){
    int cnt=0;
    while(!(x&1))
        cnt++,x>>=1;
    return 1<<cnt;
}
void Add(int x,int y){
    if(x>n)
        return;
    c[x]+=y;
    Add(x+Lowbit(x),y);
}
int Sum(int x){
    if(x==0)
        return 0;
    return c[x]+Sum(x-Lowbit(x));
}
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        scanf("%d",&s[i]);
        s[i]+=s[i-1];
        c[i]=s[i]-s[i-Lowbit(i)];
    }
    while(m--){
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(op==1)
            Add(x,y);
        else
            printf("%d\n",Sum(y)-Sum(x-1));
    }
    return 0;
}
